children.text:
*, *::before, *::after { box-sizing: border-box; }

body {
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", "Noto Sans",
               Helvetica, Arial, sans-serif;
  font-size: 16px;
  line-height: 1.5;
  color: #1f2328;
  background-color: #ffffff;
  margin: 0;
  padding: 0;
}

.gh-header {
  background: #f6f8fa;
  border-bottom: 1px solid #d0d7de;
  padding: 10px 16px;
  font-size: 13px;
  font-weight: 600;
  color: #1f2328;
}

.gh-content {
  max-width: 1012px;
  margin: 0 auto;
  padding: 32px 16px;
}

.gh-hero {
  margin-bottom: 24px;
}
.gh-hero h1 {
  font-size: 28px;
  font-weight: 600;
  margin: 0 0 8px;
  color: #1f2328;
}
.gh-hero p {
  color: #57606a;
  margin: 0;
  font-size: 14px;
}

/* File list table */
.file-table {
  width: 100%;
  border-collapse: collapse;
  border: 1px solid #d0d7de;
  border-radius: 6px;
  overflow: hidden;
  font-size: 14px;
}

.file-table thead tr {
  background: #f6f8fa;
}
.file-table th {
  padding: 8px 16px;
  text-align: left;
  font-weight: 600;
  color: #57606a;
  border-bottom: 1px solid #d0d7de;
  white-space: nowrap;
}
.file-table td {
  padding: 8px 16px;
  border-bottom: 1px solid #d0d7de;
  vertical-align: middle;
}
.file-table tr:last-child td {
  border-bottom: none;
}
.file-table tbody tr:hover {
  background: #f6f8fa;
}

/* File icon + link */
.file-link {
  display: flex;
  align-items: center;
  gap: 8px;
  color: #0969da;
  text-decoration: none;
  font-weight: 500;
}
.file-link:hover { text-decoration: underline; }
.file-link svg { color: #57606a; flex-shrink: 0; }

/* Tags/badges */
.tag {
  display: inline-block;
  padding: 2px 6px;
  border-radius: 2em;
  font-size: 11px;
  font-weight: 500;
  background: #ddf4ff;
  color: #0550ae;
  border: 1px solid #54aeff66;
}
.tag.synthetic {
  background: #fff8c5;
  color: #9a6700;
  border-color: #d4a72c66;
}

/* Stats bar */
.stats-bar {
  display: flex;
  gap: 24px;
  padding: 16px 0;
  border-bottom: 1px solid #d0d7de;
  margin-bottom: 24px;
  font-size: 13px;
  color: #57606a;
}
.stats-bar strong { color: #1f2328; }

@media (max-width: 767px) {
  .gh-content { padding: 16px 12px; }
}
